# capacity_model.py
# Model engineer-week capacity and initiative requirements for portfolio planning.

from dataclasses import dataclass, field
from typing import Optional

@dataclass
class Engineer:
    name: str
    team: str
    available_weeks: float        # weeks available this quarter (after PTO, on-call, meetings)
    skill_tags: list[str]         # ["python", "ml", "infra", "frontend"]

@dataclass
class Initiative:
    initiative_id: str
    title: str
    priority: str                 # "P0" | "P1" | "P2" | "P3"
    weighted_score: float
    estimated_weeks: float        # best estimate; treat as a range ±30%
    required_skills: list[str]    # skills needed; must match at least one engineer
    depends_on: list[str] = field(default_factory=list)   # initiative_ids
    assigned_engineer: Optional[str] = None
    start_week: Optional[int] = None
    end_week: Optional[int] = None

@dataclass
class QuarterPlan:
    quarter: str                   # "Q3-2026"
    total_weeks: int               # calendar weeks in the quarter (13)
    engineers: list[Engineer]
    initiatives: list[Initiative]

    def total_available_capacity(self) -> float:
        return sum(e.available_weeks for e in self.engineers)

    def committed_capacity(self) -> float:
        return sum(
            i.estimated_weeks for i in self.initiatives
            if i.priority in ("P0", "P1") and i.assigned_engineer
        )

    def utilization_pct(self) -> float:
        total = self.total_available_capacity()
        return self.committed_capacity() / total * 100 if total else 0

    def unassigned_p0(self) -> list[Initiative]:
        return [i for i in self.initiatives if i.priority == "P0" and not i.assigned_engineer]

# dependency_graph.py
# Model initiative dependencies and detect scheduling conflicts.

from dataclasses import dataclass, field
from collections import defaultdict, deque

@dataclass
class DependencyGraph:
    """
    Directed graph where edge A -> B means "B depends on A (A must finish first)".
    """
    edges: dict[str, list[str]] = field(default_factory=lambda: defaultdict(list))

    def add_dependency(self, prerequisite: str, dependent: str) -> None:
        self.edges[prerequisite].append(dependent)

    def topological_sort(self, initiative_ids: list[str]) -> list[str]:
        """
        Return initiatives in the order they can be started.
        Raises ValueError if there is a circular dependency.
        """
        in_degree: dict[str, int] = {i: 0 for i in initiative_ids}
        for prereq, deps in self.edges.items():
            for dep in deps:
                if dep in in_degree:
                    in_degree[dep] += 1

        queue = deque([i for i in initiative_ids if in_degree[i] == 0])
        order = []
        while queue:
            node = queue.popleft()
            order.append(node)
            for dep in self.edges.get(node, []):
                if dep in in_degree:
                    in_degree[dep] -= 1
                    if in_degree[dep] == 0:
                        queue.append(dep)

        unresolved = [i for i in initiative_ids if in_degree.get(i, 0) > 0]
        if unresolved:
            raise ValueError(f"Circular dependency detected among: {unresolved}")
        return order

    def critical_path(self, efforts: dict[str, float]) -> tuple[list[str], float]:
        """
        Find the sequence of dependent initiatives with the largest total effort.
        This is the minimum time the portfolio takes even with unlimited engineers.
        """
        ids = list(efforts.keys())
        order = self.topological_sort(ids)
        earliest_end: dict[str, float] = {}
        path_to: dict[str, list[str]] = {}

        for init_id in order:
            # Find latest finishing prerequisite
            prereqs = [p for p, deps in self.edges.items() if init_id in deps and p in efforts]
            if prereqs:
                best_prereq = max(prereqs, key=lambda p: earliest_end.get(p, 0))
                start = earliest_end.get(best_prereq, 0)
                path_to[init_id] = path_to.get(best_prereq, [best_prereq]) + [init_id]
            else:
                start = 0
                path_to[init_id] = [init_id]
            earliest_end[init_id] = start + efforts.get(init_id, 0)

        latest = max(earliest_end, key=lambda k: earliest_end[k])
        return path_to[latest], earliest_end[latest]
